import{_ as t,c as s,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"What is Superpowers: Software Development Lifecycle Workflow for AI Coding Agents | Superpowers Tutorial","description":"Learn how Superpowers provides a complete software development lifecycle workflow for AI agents with 14 composable skills. Enforces best practices like TDD, systematic debugging, and collaboration to solve common AI agent issues, improving code quality, design clarity, and iteration speed. Supports Claude Code, OpenCode, and Codex platforms with automatic skill triggering.","frontmatter":{"title":"What is Superpowers: Software Development Lifecycle Workflow for AI Coding Agents | Superpowers Tutorial","sidebarTitle":"What is Superpowers","subtitle":"What is Superpowers: Complete Development Workflow for AI Coding Agents","description":"Learn how Superpowers provides a complete software development lifecycle workflow for AI agents with 14 composable skills. Enforces best practices like TDD, systematic debugging, and collaboration to solve common AI agent issues, improving code quality, design clarity, and iteration speed. Supports Claude Code, OpenCode, and Codex platforms with automatic skill triggering.","tags":["Getting Started","AI Coding Agents","Workflow","Best Practices"],"prerequisite":[],"order":10},"headers":[],"relativePath":"obra/superpowers/start/superpowers-intro/index.md","filePath":"obra/superpowers/start/superpowers-intro/index.md"}'),o={name:"obra/superpowers/start/superpowers-intro/index.md"};function a(l,e,n,d,p,c){return i(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="what-is-superpowers-complete-development-workflow-for-ai-coding-agents" tabindex="-1">What is Superpowers: Complete Development Workflow for AI Coding Agents <a class="header-anchor" href="#what-is-superpowers-complete-development-workflow-for-ai-coding-agents" aria-label="Permalink to &quot;What is Superpowers: Complete Development Workflow for AI Coding Agents&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>By the end of this chapter, you will:</p><ul><li>Understand <strong>what Superpowers is</strong> and how it changes the way AI agents work</li><li>Know <strong>why you need it</strong>—identify common problems and limitations of AI agents</li><li>Master <strong>how the skill system works</strong>—how skills auto-trigger and priority rules</li><li>Learn about <strong>14 core skills</strong>—how they cover the complete software development lifecycle</li></ul><hr><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><p>If you&#39;ve used Claude Code, OpenCode, or Codex, you&#39;ve likely encountered these situations:</p><table tabindex="0"><thead><tr><th>AI Agent Problems</th><th>Real Scenarios</th></tr></thead><tbody><tr><td><strong>Skipping design, writing code directly</strong></td><td>You say &quot;add user authentication&quot; and it starts writing code immediately without asking about JWT vs Session, or whether two-factor authentication is needed</td></tr><tr><td><strong>Lack of test-driven development discipline</strong></td><td>Writes feature code first, then remembers to write tests, or commits without tests at all</td></tr><tr><td><strong>Ad-hoc debugging</strong></td><td>Tests fail, it modifies code based on intuition, tries a few times until it &quot;seems fixed,&quot; but the root cause isn&#39;t found</td></tr><tr><td><strong>Lack of collaboration standards</strong></td><td>When multiple tasks run in parallel, there&#39;s no clear priority. Code review becomes an afterthought</td></tr></tbody></table><p>These problems aren&#39;t because AI models aren&#39;t smart enough, but rather <strong>lack systematic workflow constraints</strong>. Superpowers exists to solve this problem.</p><hr><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p><strong>What is Superpowers?</strong></p><p>Superpowers is a complete software development lifecycle workflow built from <strong>14 composable &quot;Skills&quot;</strong> and initial instructions, ensuring that AI coding agents are forced to follow best practices.</p><div class="info custom-block"><p class="custom-block-title">What is a &quot;Skill&quot;?</p><p>A &quot;Skill&quot; is a Markdown file that defines a specific workflow, containing:</p><ul><li>Trigger conditions (when to use this skill)</li><li>Workflow diagram (how to execute step by step)</li><li>Quick reference table (key points)</li><li>Common error warnings (Red Flags)</li></ul><p>Skills are not &quot;suggestions&quot; but &quot;mandatory rules.&quot; AI agents must check if an applicable skill exists before executing tasks.</p></div><p><strong>How does it work?</strong></p><p>Traditional AI agent workflow:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User request → Generate code directly → Submit</span></span></code></pre></div><p>Superpowers-enhanced workflow:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User request → Check skills → Call skill → Execute by process → Verify → Complete</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Mandatory Skill Invocation Rule</p><p>Even if there&#39;s only a <strong>1% chance</strong> that a skill applies, the AI agent <strong>must invoke it</strong>. This is not optional, non-negotiable, and cannot be &quot;rationalized&quot; away.</p><p>For example, the agent thinks: &quot;This is just a simple problem, no skill needed&quot; → ❌ Wrong! Must check skills first.</p></div><hr><h2 id="how-the-skill-system-works" tabindex="-1">How the Skill System Works <a class="header-anchor" href="#how-the-skill-system-works" aria-label="Permalink to &quot;How the Skill System Works&quot;">​</a></h2><h3 id="skill-invocation-flow" tabindex="-1">Skill Invocation Flow <a class="header-anchor" href="#skill-invocation-flow" aria-label="Permalink to &quot;Skill Invocation Flow&quot;">​</a></h3><p>When an AI agent receives a task, it follows this workflow:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[User message] --&gt; B{Is a skill applicable?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|Yes, even 1%| C[Call Skill tool]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Announce: Using skill X to do Y]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E{Is there a checklist?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt;|Yes| F[Create TodoWrite task]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt;|No| G[Execute directly]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; H[Execute by skill steps]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; I[Complete task]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|Absolutely not applicable| I</span></span></code></pre></div><h3 id="red-flags-common-misconceptions" tabindex="-1">Red Flags: Common Misconceptions <a class="header-anchor" href="#red-flags-common-misconceptions" aria-label="Permalink to &quot;Red Flags: Common Misconceptions&quot;">​</a></h3><p>AI agents often have these &quot;rationalized&quot; thoughts when skipping skill checks:</p><table tabindex="0"><thead><tr><th>AI Agent Thoughts</th><th>Reality</th></tr></thead><tbody><tr><td>&quot;This is just a simple problem&quot;</td><td>Problems are tasks too, must check skills</td></tr><tr><td>&quot;I need more context&quot;</td><td>Skill checking happens before asking questions</td></tr><tr><td>&quot;Let me explore the codebase first&quot;</td><td>Skills tell you how to explore, check skills first</td></tr><tr><td>&quot;I can quickly check git/files&quot;</td><td>Files lack conversation context, must check skills</td></tr><tr><td>&quot;This skill is too heavy&quot;</td><td>Simple things become complex, use the skill</td></tr><tr><td>&quot;I know this skill&quot;</td><td>Skills get updated, must read the current version</td></tr></tbody></table><h3 id="skill-priority" tabindex="-1">Skill Priority <a class="header-anchor" href="#skill-priority" aria-label="Permalink to &quot;Skill Priority&quot;">​</a></h3><p>When multiple skills might apply, select in this order:</p><ol><li><strong>Process skills first</strong> (like brainstorming, debugging) — determine <strong>how</strong> to handle the task</li><li><strong>Implementation skills second</strong> (like frontend-design) — guide specific execution</li></ol><p><strong>Examples</strong>:</p><ul><li>&quot;Let&#39;s build X&quot; → brainstorming first, then implementation skills</li><li>&quot;Fix this bug&quot; → debugging first, then domain-specific skills</li></ul><h3 id="skill-types" tabindex="-1">Skill Types <a class="header-anchor" href="#skill-types" aria-label="Permalink to &quot;Skill Types&quot;">​</a></h3><ul><li><strong>Rigid</strong>: Like TDD, debugging — must be followed precisely, discipline cannot be adjusted</li><li><strong>Flexible</strong>: Like design patterns — can adjust principles based on context</li></ul><p>The skill itself will tell you which type it is.</p><hr><h2 id="superpowers-14-core-skills" tabindex="-1">Superpowers&#39; 14 Core Skills <a class="header-anchor" href="#superpowers-14-core-skills" aria-label="Permalink to &quot;Superpowers&#39; 14 Core Skills&quot;">​</a></h2><h3 id="skill-library-categories" tabindex="-1">Skill Library Categories <a class="header-anchor" href="#skill-library-categories" aria-label="Permalink to &quot;Skill Library Categories&quot;">​</a></h3><p><strong>Testing Skills</strong></p><ul><li><strong>test-driven-development</strong>: RED-GREEN-REFACTOR cycle, forces writing tests first</li></ul><p><strong>Debugging Skills</strong></p><ul><li><strong>systematic-debugging</strong>: Four-stage root cause analysis process</li><li><strong>verification-before-completion</strong>: Ensure it&#39;s truly fixed, verification first</li></ul><p><strong>Collaboration Skills</strong></p><ul><li><strong>brainstorming</strong>: Socratic design refinement, clarifying requirements through questions</li><li><strong>writing-plans</strong>: Detailed implementation plans, each task 2-5 minutes</li><li><strong>executing-plans</strong>: Batch execute plans, human checkpoints</li><li><strong>dispatching-parallel-agents</strong>: Concurrent sub-agent workflows</li><li><strong>requesting-code-review</strong>: Pre-review checklists</li><li><strong>receiving-code-review</strong>: How to respond to code review feedback</li><li><strong>using-git-worktrees</strong>: Using Git worktrees to create isolated development environments</li><li><strong>finishing-a-development-branch</strong>: Branch completion workflow (merge/PR/keep/abandon)</li><li><strong>subagent-driven-development</strong>: Rapid iteration, two-stage review (spec compliance, code quality)</li></ul><p><strong>Meta Skills</strong></p><ul><li><strong>writing-skills</strong>: Best practices guide for creating new skills</li><li><strong>using-superpowers</strong>: Skill system entry point (this chapter is about this skill)</li></ul><h3 id="complete-development-workflow" tabindex="-1">Complete Development Workflow <a class="header-anchor" href="#complete-development-workflow" aria-label="Permalink to &quot;Complete Development Workflow&quot;">​</a></h3><p>When you say &quot;Let&#39;s build a new feature,&quot; Superpowers will automatically trigger the following workflow:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[User request] --&gt; B[brainstorming]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[using-git-worktrees]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[writing-plans]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[subagent-driven-development]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[test-driven-development]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[requesting-code-review]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[finishing-a-development-branch]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e3f2fd</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#bbdefb</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#bbdefb</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#bbdefb</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#bbdefb</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style F fill:#bbdefb</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#bbdefb</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style H fill:#90caf9</span></span></code></pre></div><p><strong>Each step triggers automatically</strong>, no manual intervention needed.</p><h3 id="philosophical-principles" tabindex="-1">Philosophical Principles <a class="header-anchor" href="#philosophical-principles" aria-label="Permalink to &quot;Philosophical Principles&quot;">​</a></h3><p>Superpowers is designed based on four principles:</p><table tabindex="0"><thead><tr><th>Principle</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Test-Driven Development</strong></td><td>Test first, always write tests first</td></tr><tr><td><strong>Systematic over ad-hoc</strong></td><td>Systematic processes beat random guessing</td></tr><tr><td><strong>Complexity reduction</strong></td><td>Simplicity is the primary goal (YAGNI principle)</td></tr><tr><td><strong>Evidence over claims</strong></td><td>Must verify before declaring success (evidence first)</td></tr></tbody></table><hr><h2 id="why-superpowers-is-useful" tabindex="-1">Why Superpowers is Useful? <a class="header-anchor" href="#why-superpowers-is-useful" aria-label="Permalink to &quot;Why Superpowers is Useful?&quot;">​</a></h2><h3 id="benefits-for-ai-agents" tabindex="-1">Benefits for AI Agents <a class="header-anchor" href="#benefits-for-ai-agents" aria-label="Permalink to &quot;Benefits for AI Agents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Problem</th><th>Superpowers Solution</th></tr></thead><tbody><tr><td>Skipping design, writing code directly</td><td>brainstorming skill forces clarifying requirements first</td></tr><tr><td>Missing tests, problems found only after commit</td><td>TDD skill forces RED-GREEN-REFACTOR cycle</td></tr><tr><td>Ad-hoc debugging, multiple fixes without finding root cause</td><td>systematic-debugging skill provides four-stage process</td></tr><tr><td>Chaotic tasks, unclear priorities</td><td>writing-plans skill breaks tasks into 2-5 minute chunks</td></tr><tr><td>Code review becomes an afterthought</td><td>requesting-code-review skill automatically reviews after each task</td></tr></tbody></table><h3 id="benefits-for-you" tabindex="-1">Benefits for You <a class="header-anchor" href="#benefits-for-you" aria-label="Permalink to &quot;Benefits for You&quot;">​</a></h3><ul><li><strong>More reliable code</strong>: Enforced test-driven development reduces bugs</li><li><strong>Clearer design</strong>: brainstorming ensures correct requirement understanding</li><li><strong>Faster iteration</strong>: Subagent-driven development lets AI work independently for hours</li><li><strong>Trackable progress</strong>: Every step has checklists and verification requirements</li><li><strong>Consistent quality</strong>: Same workflow regardless of who uses it</li></ul><hr><h2 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h2><ul><li><strong>Superpowers</strong> is a complete software development lifecycle workflow that ensures AI agents are forced to follow best practices through 14 composable skills</li><li><strong>Skills are not suggestions</strong>, but mandatory rules — AI agents must check and invoke applicable skills before executing tasks</li><li><strong>The skill system</strong> triggers automatically without manual intervention, covering the complete flow from design to deployment</li><li><strong>Four principles</strong>: TDD, systematic, simplification, evidence first are the core guidance for all skills</li></ul><hr><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../quick-start/">Quick Start: Get Started in 5 Minutes</a></strong>.</p><p>You&#39;ll experience hands-on:</p><ul><li>Using Superpowers&#39; basic workflow</li><li>Triggering brainstorming skill to clarify requirements</li><li>Experiencing AI agent&#39;s &quot;auto-navigation&quot; capability</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Superpowers definition</td><td><a href="https://github.com/obra/superpowers/blob/main/README.md#L3" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>3</td></tr><tr><td>Workflow description</td><td><a href="https://github.com/obra/superpowers/blob/main/README.md#L5-L15" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>5-15</td></tr><tr><td>Basic workflow</td><td><a href="https://github.com/obra/superpowers/blob/main/README.md#L80-L96" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>80-96</td></tr><tr><td>Skill library categories</td><td><a href="https://github.com/obra/superpowers/blob/main/README.md#L98-L122" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>98-122</td></tr><tr><td>Philosophical principles</td><td><a href="https://github.com/obra/superpowers/blob/main/README.md#L124-L129" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>124-129</td></tr><tr><td>Plugin metadata</td><td><a href="https://github.com/obra/superpowers/blob/main/.claude-plugin/plugin.json#L1-L13" target="_blank" rel="noreferrer"><code>.claude-plugin/plugin.json</code></a></td><td>1-13</td></tr><tr><td>Skill invocation rule</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L6-L12" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>6-12</td></tr><tr><td>Skill invocation flow diagram</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L26-L46" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>26-46</td></tr><tr><td>Red Flags list</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L48-L64" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>48-64</td></tr><tr><td>Skill priority</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L68-L75" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>68-75</td></tr><tr><td>Skill types</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L77-L83" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>77-83</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li>Plugin version: <code>&quot;version&quot;: &quot;4.1.1&quot;</code></li></ul><p><strong>Key Rules</strong>:</p><ul><li><strong>Mandatory invocation rule</strong>: Even with 1% possibility, must invoke skill (<code>using-superpowers/SKILL.md:7</code>)</li><li><strong>No choice</strong>: If a skill applies, AI agent has no discretion (<code>using-superpowers/SKILL.md:9</code>)</li></ul></details>`,69)])])}const g=t(o,[["render",a]]);export{u as __pageData,g as default};
